import logging
from flask import Flask, request, jsonify

app = Flask(__name__)

# Set up logging
logging.basicConfig(filename='app.log', level=logging.DEBUG)
logger = logging.getLogger()

@app.route('/api/v1/users', methods=['GET'])
def get_users():
    # Log request headers and body data for debugging
    logger.info('Request headers: %s', request.headers)
    logger.info('Request body: %s', request.get_data())

    # Log user information for troubleshooting failed logins
    logger.info('User ID: %s', request.args.get('user_id'))
    logger.info('Authentication token: %s', request.headers.get('Authorization'))

    # Return a JSON response with the list of users
    return jsonify([{'name': 'John Doe'}, {'name': 'Jane Doe'}])